// src/pages/KhaiBaoCoSo.js
import React, { useState } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx'; // Import thư viện xlsx
import './KhaiBaoCoSo.css'; // Import file CSS

function KhaiBaoCoSo() {
  const [form, setForm] = useState({
    // Thông tin cơ sở
    tenCoSo: '',
    tinhThanhPho: '',
    xaPhuong: '',
    diaChiCoSo: '',
    vido: '',
    kinhdo: '',
    loaiHinhCoSo: '',
    ngayThanhLap: '',
    giayPhepKinhDoanh: '',

    // Người đại diện
    tenNguoiDaiDien: '',
    namSinh: '',
    soCCCD: '',
    ngayCapCCCD: '',
    noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '',
    diaChiNguoiDaiDien: '',
    emailNguoiDaiDien: '',

    // Cơ sở gây nuôi
    mucDichNuoi: '',
    hinhThucNuoi: '',
    maSoCoSoGayNuoi: '',

    // Cơ sở kinh doanh, chế biến gỗ
    loaiHinhKinhDoanhGo: '',
    nganhNgheKinhDoanhGo: '',

    // Mới: Loại cơ sở đăng ký
    loaiCoSoDangKy: '', 
  });

  const [successMessage, setSuccessMessage] = useState('');
  const [errorMessage, setErrorMessage] = useState('');
  const [excelFile, setExcelFile] = useState(null); // State để lưu trữ file Excel
  const [excelData, setExcelData] = useState([]); // State để lưu trữ dữ liệu từ Excel

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSuccessMessage('');
    setErrorMessage('');

    // Ghi log trạng thái form hiện tại để gỡ lỗi
    console.log('Trạng thái form khi submit:', form);

    // Logic xác thực: Kiểm tra các trường có giá trị khác rỗng sau khi loại bỏ khoảng trắng
    const isGayNuoiFilled = (form.mucDichNuoi && form.mucDichNuoi.trim() !== '') || 
                           (form.hinhThucNuoi && form.hinhThucNuoi.trim() !== '') || 
                           (form.maSoCoSoGayNuoi && form.maSoCoSoGayNuoi.trim() !== '');

    const isKinhDoanhGoFilled = (form.loaiHinhKinhDoanhGo && form.loaiHinhKinhDoanhGo.trim() !== '') ||
                               (form.nganhNgheKinhDoanhGo && form.nganhNgheKinhDoanhGo.trim() !== '');

    // Ghi log để gỡ lỗi
    console.log('Kiểm tra Cơ sở gây nuôi đã điền:', isGayNuoiFilled);
    console.log('Kiểm tra Cơ sở kinh doanh gỗ đã điền:', isKinhDoanhGoFilled);

    // Logic xác thực dựa trên loaiCoSoDangKy
    if (form.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi') {
      if (!isGayNuoiFilled) {
        setErrorMessage('Vui lòng điền đầy đủ thông tin cho mục "Cơ sở gây nuôi".');
        return;
      }
      if (isKinhDoanhGoFilled) {
        setErrorMessage('Không được điền thông tin "Cơ sở kinh doanh, chế biến gỗ" khi đã chọn "Đăng ký cơ sở gây nuôi".');
        return;
      }
    } else if (form.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ') {
      if (!isKinhDoanhGoFilled) {
        setErrorMessage('Vui lòng điền đầy đủ thông tin cho mục "Cơ sở kinh doanh, chế biến gỗ".');
        return;
      }
      if (isGayNuoiFilled) {
        setErrorMessage('Không được điền thông tin "Cơ sở gây nuôi" khi đã chọn "Đăng ký cơ sở kinh doanh, chế biến gỗ".');
        return;
      }
    } else { // Nếu chưa chọn loại cơ sở đăng ký
      if (isGayNuoiFilled && isKinhDoanhGoFilled) {
        setErrorMessage('Bạn chỉ có thể khai báo thông tin cho Cơ sở gây nuôi HOẶC Cơ sở kinh doanh, chế biến gỗ, không được cả hai.');
        return;
      }
      if (!isGayNuoiFilled && !isKinhDoanhGoFilled) {
        setErrorMessage('Vui lòng chọn "Loại cơ sở đăng ký" và điền thông tin tương ứng.');
        return;
      }
    }

    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setErrorMessage('Bạn chưa đăng nhập. Vui lòng đăng nhập lại.');
        return;
      }

      const response = await axios.post(
        'http://localhost:10000/api/farms', // Đảm bảo API endpoint này đúng
        form, // Gửi trực tiếp state 'form'
        {
          headers: {
            Authorization: `Bearer ${token}`
          }
        }
      );

      console.log('Success:', response.data);
      setSuccessMessage('Thông tin cơ sở đã được lưu thành công!');
      setForm({ // Reset form sau khi thành công
        tenCoSo: '',
        tinhThanhPho: '',
        xaPhuong: '',
        diaChiCoSo: '',
        vido: '',
        kinhdo: '',
        loaiHinhCoSo: '',
        ngayThanhLap: '',
        giayPhepKinhDoanh: '',
        tenNguoiDaiDien: '',
        namSinh: '',
        soCCCD: '',
        ngayCapCCCD: '',
        noiCapCCCD: '',
        soDienThoaiNguoiDaiDien: '',
        diaChiNguoiDaiDien: '',
        emailNguoiDaiDien: '',
        mucDichNuoi: '',
        hinhThucNuoi: '',
        maSoCoSoGayNuoi: '',
        loaiHinhKinhDoanhGo: '',
        nganhNgheKinhDoanhGo: '',
        loaiCoSoDangKy: '', // Reset trường mới
      });
    } catch (error) {
      setErrorMessage('Đã xảy ra lỗi khi lưu thông tin. Vui lòng thử lại.');
      console.error('Error saving farm:', error.response?.data || error.message);

      if (error.response && error.response.data && error.response.data.errors) {
        const validationErrors = Object.values(error.response.data.errors).map(err => err.message).join('; ');
        setErrorMessage(`Lỗi xác thực: ${validationErrors}`);
      } else if (error.response && error.response.data && error.response.data.message) {
        setErrorMessage(`Đã xảy ra lỗi: ${error.response.data.message}`);
      }
    }
  };

  // Hàm xử lý tải lên file Excel
  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      setExcelFile(file);
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const data = new Uint8Array(event.target.result);
          const workbook = XLSX.read(data, { type: 'array' });
          const sheetName = workbook.SheetNames[0]; // Lấy tên sheet đầu tiên
          const worksheet = workbook.Sheets[sheetName];
          const json = XLSX.utils.sheet_to_json(worksheet); // Chuyển đổi sang JSON

          // Map dữ liệu từ Excel sang định dạng form của bạn
          // Bạn cần đảm bảo các cột trong Excel khớp với các trường trong form
          const mappedData = json.map(row => ({
            tenCoSo: row['Tên cơ sở'] || '',
            tinhThanhPho: row['Tỉnh (Thành phố)'] || '',
            xaPhuong: row['Xã (Phường)'] || '',
            diaChiCoSo: row['Địa chỉ'] || '',
            vido: row['Vĩ độ'] || '',
            kinhdo: row['Kinh độ'] || '',
            loaiHinhCoSo: row['Loại hình cơ sở'] || '',
            ngayThanhLap: row['Ngày thành lập'] ? new Date(Math.round((row['Ngày thành lập'] - 25569) * 86400 * 1000)).toISOString().split('T')[0] : '', // Chuyển đổi số Excel date sang YYYY-MM-DD
            giayPhepKinhDoanh: row['Số giấy phép kinh doanh'] || '',
            tenNguoiDaiDien: row['Họ và tên người đại diện'] || '',
            namSinh: row['Năm sinh'] || '',
            soCCCD: row['Số CCCD/Hộ chiếu'] || '',
            ngayCapCCCD: row['Ngày cấp CCCD'] ? new Date(Math.round((row['Ngày cấp CCCD'] - 25569) * 86400 * 1000)).toISOString().split('T')[0] : '',
            noiCapCCCD: row['Nơi cấp CCCD'] || '',
            soDienThoaiNguoiDaiDien: row['Số điện thoại người đại diện'] || '',
            diaChiNguoiDaiDien: row['Địa chỉ người đại diện'] || '',
            emailNguoiDaiDien: row['Email người đại diện'] || '',
            mucDichNuoi: row['Mục đích nuôi'] || '',
            hinhThucNuoi: row['Hình thức nuôi'] || '',
            maSoCoSoGayNuoi: row['Mã số cơ sở gây nuôi'] || '',
            loaiHinhKinhDoanhGo: row['Loại hình kinh doanh gỗ'] || '',
            nganhNgheKinhDoanhGo: row['Ngành nghề kinh doanh gỗ'] || '',
            loaiCoSoDangKy: row['Loại cơ sở đăng ký'] || '',
            // Thêm các trường khác nếu có trong Excel và form của bạn
          }));
          setExcelData(mappedData);
          setSuccessMessage(`Đã đọc thành công ${json.length} dòng dữ liệu từ Excel. Vui lòng nhấn "Tải lên hàng loạt" để lưu.`);
          setErrorMessage('');
        } catch (error) {
          setErrorMessage('Lỗi khi đọc file Excel. Vui lòng đảm bảo file đúng định dạng.');
          console.error('Error reading Excel file:', error);
        }
      };
      reader.readAsArrayBuffer(file);
    }
  };

  // Hàm xử lý tải lên dữ liệu hàng loạt từ Excel
  const handleBulkSubmit = async () => {
    setSuccessMessage('');
    setErrorMessage('');

    if (excelData.length === 0) {
      setErrorMessage('Không có dữ liệu từ Excel để tải lên.');
      return;
    }

    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setErrorMessage('Bạn chưa đăng nhập. Vui lòng đăng nhập lại.');
        return;
      }

      // Gửi mảng dữ liệu đã phân tích từ Excel
      const response = await axios.post(
        'http://localhost:10000/api/farms/bulk', // API endpoint mới cho tải lên hàng loạt
        excelData, // Gửi mảng các đối tượng farm
        {
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json'
          }
        }
      );

      console.log('Bulk upload success:', response.data);
      setSuccessMessage(`Đã lưu thành công ${response.data.savedCount || excelData.length} cơ sở từ file Excel!`);
      setExcelFile(null); // Reset file
      setExcelData([]); // Reset dữ liệu Excel
    } catch (error) {
      setErrorMessage('Đã xảy ra lỗi khi tải lên dữ liệu hàng loạt. Vui lòng thử lại.');
      console.error('Error bulk uploading farms:', error.response?.data || error.message);

      if (error.response && error.response.data && error.response.data.message) {
        setErrorMessage(`Lỗi: ${error.response.data.message}`);
      } else if (error.response && error.response.data && error.response.data.errors) {
        const validationErrors = Object.values(error.response.data.errors).map(err => err.message).join('; ');
        setErrorMessage(`Lỗi xác thực: ${validationErrors}`);
      }
    }
  };


  return (
    <div className="khai-bao-container">
      <h1>Khai báo cơ sở</h1>
      {successMessage && <p className="success-message">{successMessage}</p>}
      {errorMessage && <p className="error-message">{errorMessage}</p>}
      
      {/* Phần tải lên Excel */}
      <section className="khai-bao-section">
        <h2>Tải lên từ Excel</h2>
        <div className="form-group">
          <label htmlFor="excelUpload">Chọn file Excel (.xlsx, .xls):</label>
          <input 
            type="file" 
            id="excelUpload" 
            accept=".xlsx, .xls" 
            onChange={handleFileUpload} 
          />
        </div>
        {excelData.length > 0 && (
          <div className="excel-preview-info">
            <p>Đã đọc được {excelData.length} dòng dữ liệu từ file Excel.</p>
            <button onClick={handleBulkSubmit} className="submit-button bulk-upload-button">
              Tải lên hàng loạt ({excelData.length} cơ sở)
            </button>
          </div>
        )}
        <p className="note-text">
          Lưu ý: File Excel cần có các cột với tiêu đề khớp chính xác với các trường trong form (ví dụ: "Tên cơ sở", "Tỉnh (Thành phố)", "Họ và tên người đại diện", v.v.).
        </p>
      </section>

      <hr className="section-divider" /> {/* Đường phân cách */}

      {/* Phần khai báo từng cơ sở */}
      <form onSubmit={handleSubmit}>
        <section className="khai-bao-section">
          <h2>Thông tin cơ sở (Khai báo thủ công)</h2>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="tenCoSo">Tên cơ sở:</label>
              <input type="text" id="tenCoSo" name="tenCoSo" value={form.tenCoSo} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="tinhThanhPho">Tỉnh (Thành phố):</label>
              <input type="text" id="tinhThanhPho" name="tinhThanhPho" value={form.tinhThanhPho} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="xaPhuong">Xã (Phường):</label>
              <input type="text" id="xaPhuong" name="xaPhuong" value={form.xaPhuong} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="diaChiCoSo">Địa chỉ:</label>
              <input type="text" id="diaChiCoSo" name="diaChiCoSo" value={form.diaChiCoSo} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="vido">Vĩ độ:</label>
              <input type="text" id="vido" name="vido" value={form.vido} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="kinhdo">Kinh độ:</label>
              <input type="text" id="kinhdo" name="kinhdo" value={form.kinhdo} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="loaiHinhCoSo">Loại hình cơ sở:</label>
              <input type="text" id="loaiHinhCoSo" name="loaiHinhCoSo" value={form.loaiHinhCoSo} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="ngayThanhLap">Ngày thành lập:</label>
              <input type="date" id="ngayThanhLap" name="ngayThanhLap" value={form.ngayThanhLap} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="giayPhepKinhDoanh">Số giấy phép kinh doanh:</label>
              <input type="text" id="giayPhepKinhDoanh" name="giayPhepKinhDoanh" value={form.giayPhepKinhDoanh} onChange={handleChange} />
            </div>
            {/* Mới: Loại cơ sở đăng ký */}
            <div className="form-group">
              <label htmlFor="loaiCoSoDangKy">Loại cơ sở đăng ký:</label>
              <select id="loaiCoSoDangKy" name="loaiCoSoDangKy" value={form.loaiCoSoDangKy} onChange={handleChange} required>
                <option value="">- Chọn loại cơ sở -</option>
                <option value="Đăng ký cơ sở gây nuôi">=> Đăng ký cơ sở gây nuôi</option>
                <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">=> Đăng ký cơ sở kinh doanh,chế biến gỗ</option>
              </select>
            </div>
          </div>
        </section>

        <section className="khai-bao-section">
          <h2>Người đại diện</h2>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="tenNguoiDaiDien">Họ và tên:</label>
              <input type="text" id="tenNguoiDaiDien" name="tenNguoiDaiDien" value={form.tenNguoiDaiDien} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="namSinh">Năm sinh:</label>
              <input type="number" id="namSinh" name="namSinh" value={form.namSinh} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="soCCCD">Số CCCD/Hộ chiếu:</label>
              <input type="text" id="soCCCD" name="soCCCD" value={form.soCCCD} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="ngayCapCCCD">Ngày cấp:</label>
              <input type="date" id="ngayCapCCCD" name="ngayCapCCCD" value={form.ngayCapCCCD} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="noiCapCCCD">Nơi cấp:</label>
              <input type="text" id="noiCapCCCD" name="noiCapCCCD" value={form.noiCapCCCD} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="soDienThoaiNguoiDaiDien">Số điện thoại:</label>
              <input type="tel" id="soDienThoaiNguoiDaiDien" name="soDienThoaiNguoiDaiDien" value={form.soDienThoaiNguoiDaiDien} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="diaChiNguoiDaiDien">Địa chỉ:</label>
              <input type="text" id="diaChiNguoiDaiDien" name="diaChiNguoiDaiDien" value={form.diaChiNguoiDaiDien} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="emailNguoiDaiDien">Email:</label>
              <input type="email" id="emailNguoiDaiDien" name="emailNguoiDaiDien" value={form.emailNguoiDaiDien} onChange={handleChange} />
            </div>
          </div>
        </section>

        {/* Conditional rendering for Cơ sở gây nuôi */}
        {form.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' && (
          <section className="khai-bao-section">
            <h3>Cơ sở gây nuôi</h3>
            <div className="form-grid">
              <div className="form-group">
                <label htmlFor="mucDichNuoi">Mục đích nuôi:</label>
                <select id="mucDichNuoi" name="mucDichNuoi" value={form.mucDichNuoi} onChange={handleChange}>
                  <option value="">Chọn mục đích nuôi</option>
                  <option value="Nuôi thương mại">Nuôi thương mại</option>
                  <option value="Nuôi phi thương mại">Nuôi phi thương mại</option>
                </select>
              </div>
              <div className="form-group">
                <label htmlFor="hinhThucNuoi">Hình thức nuôi:</label>
                <select id="hinhThucNuoi" name="hinhThucNuoi" value={form.hinhThucNuoi} onChange={handleChange}>
                  <option value="">Chọn hình thức nuôi</option>
                  <option value="Sinh trưởng">Sinh trưởng</option>
                  <option value="Sinh sản">Sinh sản</option>
                  <option value="Sinh trưởng và sinh sản">Sinh trưởng và sinh sản</option>
                </select>
              </div>
              <div className="form-group">
                <label htmlFor="maSoCoSoGayNuoi">Mã số cơ sở:</label>
                <input type="text" id="maSoCoSoGayNuoi" name="maSoCoSoGayNuoi" value={form.maSoCoSoGayNuoi} onChange={handleChange} />
              </div>
            </div>
          </section>
        )}

        {/* Conditional rendering for Cơ sở kinh doanh, chế biến gỗ */}
        {form.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ' && (
          <section className="khai-bao-section">
            <h4>Cơ sở kinh doanh, chế biến gỗ</h4>
            <div className="form-grid">
              <div className="form-group">
                <label htmlFor="loaiHinhKinhDoanhGo">Loại hình kinh doanh gỗ:</label>
                <select id="loaiHinhKinhDoanhGo" name="loaiHinhKinhDoanhGo" value={form.loaiHinhKinhDoanhGo} onChange={handleChange}>
                  <option value="">Chọn loại hình kinh doanh</option>
                  <option value="Trại cưa">Trại cưa</option>
                  <option value="Trại mộc">Trại mộc</option>
                  <option value="Trang trí nội thất">Trang trí nội thất</option>
                </select>
              </div>
              <div className="form-group">
                <label htmlFor="nganhNgheKinhDoanhGo">Ngành nghề:</label>
                <select id="nganhNgheKinhDoanhGo" name="nganhNgheKinhDoanhGo" value={form.nganhNgheKinhDoanhGo} onChange={handleChange}>
                  <option value="">Chọn ngành nghề</option>
                  <option value="Thương mại">Thương mại</option>
                  <option value="Cưa gia công và mộc">Cưa gia công và mộc</option>
                  <option value="Chế biến mộc và thương mại">Chế biến mộc và thương mại</option>
                </select>
              </div>
            </div>
          </section>
        )}

        <button type="submit" className="submit-button">Lưu thông tin</button>
      </form>
    </div>
  );
}

export default KhaiBaoCoSo;
